#include <stdio.h>
#include <stdlib.h>
#define MAX_NODES 10000

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to perform zigzag level order traversal
void zigzagTraversal(Node* root) {
    if (root == NULL) return;

    // Initialize the queue with the root node
    Node** queue = (Node**) malloc(sizeof(Node*) * MAX_NODES);
    int front = 0, rear = 0;
    queue[rear++] = root;

    // Initialize the flag for direction of traversal
    int leftToRight = 1;

    while (front < rear) {
        int size = rear - front;
        int* level = (int*) malloc(sizeof(int) * size);

        // Process all nodes at the current level
        for (int i = 0; i < size; i++) {
            Node* node = queue[front++];
            int index = (leftToRight) ? i : size - 1 - i;
            level[index] = node->val;

            if (node->left) queue[rear++] = node->left;
            if (node->right) queue[rear++] = node->right;
        }

        // Print the current level
        for (int i = 0; i < size; i++) printf("%d ", level[i]);
        printf("\n");

        // Update the direction flag for the next level
        leftToRight = !leftToRight;
    }
}

int main() {
    int N;
    scanf("%d", &N);

    // Create the tree based on the input
    Node* root = NULL;
    Node* nodes[N];
    for (int i = 0; i < N; i++) {
        nodes[i] = createNode(i + 1);
    }
    for (int i = 0; i < N - 1; i++) {
        int pi, ci;
        char Ri;
        scanf("%d %d %c", &pi, &ci, &Ri);
        if (Ri == 'L') {
            nodes[pi - 1]->left = nodes[ci - 1];
        } else {
            nodes[pi - 1]->right = nodes[ci - 1];
        }
    }
    root = nodes[0];

    // Perform zigzag level order traversal
    zigzagTraversal(root);

    return 0;
}

