import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

// Define the class for a tree node
class Node {
    int val;
    Node left;
    Node right;
    Node(int node_value) {
        val = node_value;
        left = right = null;
    }
}

public class Main {
    // Function to perform zigzag level order traversal
    public static void zigzagTraversal(Node root) {
        if (root == null) return;

        Queue<Node> nodeQueue = new LinkedList<>();
        nodeQueue.offer(root);
        boolean leftToRight = true;

        while (!nodeQueue.isEmpty()) {
            int size = nodeQueue.size();
            int[] level = new int[size];

            for (int i = 0; i < size; i++) {
                Node node = nodeQueue.poll();
                int index = (leftToRight) ? i : size - 1 - i;
                level[index] = node.val;

                if (node.left != null) nodeQueue.offer(node.left);
                if (node.right != null) nodeQueue.offer(node.right);
            }

            for (int val : level) System.out.print(val + " ");
            System.out.println();

            leftToRight = !leftToRight;
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();

        // Create the tree based on the input
        Node root = null;
        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = new Node(i + 1);
        }
        for (int i = 0; i < N - 1; i++) {
            int pi = sc.nextInt();
            int ci = sc.nextInt();
            char Ri = sc.next().charAt(0);
            if (Ri == 'L') {
                nodes[pi - 1].left = nodes[ci - 1];
            } else {
                nodes[pi - 1].right = nodes[ci - 1];
            }
        }
        root = nodes[0];

        // Perform zigzag level order traversal
        zigzagTraversal(root);
    }
}

